import React, { useContext } from 'react';
import { Container } from 'react-bootstrap'; 
import { Link } from 'react-router-dom';
import { SettingsContext } from '../context/SettingsContext'; 
import styles from './Header.module.css'; 

const Header = () => {
  const { settings } = useContext(SettingsContext);

  // El Header es recto, sin redondeo, con color de fondo oscuro.
  return (
    <header 
      className={`w-full sticky top-0 z-50 transition-all duration-300 shadow-md ${styles.header}`}
    >
      <Container className="py-3"> 
        {/* Usamos d-flex para la alineación horizontal */}
        <div className="d-flex justify-content-start align-items-center">
          
          {/* 1. Logo / Nombre del Sitio (Aplicamos la clase CSS Module) */}
          <Link 
            to="/" 
            // CRÍTICO: Usamos pure Tailwind para la alineación horizontal de imagen y texto
            // y usamos styles.logoText para anular el subrayado del Link
            className={`${styles.logoText} flex items-center space-x-2 flex-shrink-0`} 
          > 
            {/* Imagen del Logo: Usamos la ruta estándar de la carpeta public */}
            <img 
                src={`${process.env.PUBLIC_URL}/images/logo.png`} // **RUTA ASUMIDA EN PUBLIC/IMAGES/**
                alt={settings?.siteName || 'Tecnotitlán Logo'} 
                // CRÍTICO: Estilo inline para asegurar que la imagen no sea gigante (35px)
                style={{ height: '35px', width: 'auto', objectFit: 'contain' }} 
                // Si la imagen falla (404), ocultamos la imagen
                onError={(e) => { e.target.style.display = 'none'; }}
            />
            
            {/* Contenedor del Texto (stack vertical) */}
            <div className="flex flex-col items-start">
                <span className="text-white text-xl font-extrabold tracking-widest uppercase" style={{ lineHeight: 1 }}>
                  {settings?.siteName || 'TECNOTITLÁN'}
                </span>
                <span className="text-gray-400 text-xs font-light tracking-wide mt-0.5" style={{ lineHeight: 1 }}>
                  Tecnología con Raíces
                </span>
            </div>
          </Link>
          
          {/* Dejamos el espacio restante completamente vacío */}
          <div className="flex-grow"></div> 

        </div>
      </Container>
    </header>
  );
};

export default Header;
